r		(OSStatus		errorCode,								StringPtr		errorMsg);void		ErrorCheck			(OSStatus		errorCode,								StringPtr		errorMsg);//*************************************************************************************//  Error funtions//*************************************************************************************void		NonFatalError		(StringPtr		errorMsg,								StringPtr		explainMsg);void		NonFatalError		(StringPtr		errorMsg);void		NonFatalError		(long			numberError);Boolean		YesNoError			(StringPtr		errorMsg);#define		ReturnError()		if(error != noErr)return error//*************************************************************************************//  Time funtions//*************************************************************************************void		ResetDelay			(void);void		Delay				(UInt32		numOfTicks);//*************************************************************************************//  Pascal String funtions//*************************************************************************************void		pstrcpy				(StringPtr			dstString,								const StringPtr		srcString);void		pstrncpy			(StringPtr			dstString,								const StringPtr		srcString, 								const short			numToCopy);void		pstrcat				(StringPtr			dstString,								const StringPtr		srcString);short		pstrcmp				(const StringPtr	string1,								const StringPtr		string2);short		pstrlen				(const StringPtr	string);//*************************************************************************************//  Misc funtions//*************************************************************************************short		Random				(short				randomRange);#endif